var MacVimBuildInstaller = class extends BuildInstaller {
	repository = "macvim-dev/macvim";
	tags = {};
	getExecutableName() {
		return "vim";
	}
	async obtainFixedVersion(vimVersion) {
		const log = await execGit([
			"log",
			"-20",
			"--format=format:%s"
		], { cwd: this.repositoryPath(vimVersion) });
		const matched = /^\s*(?:patch|updated for version)\s+v?(\d+\.\d+\.\d+)/m.exec(log);
		if (matched) {
			const version = `v${matched[1]}`;
			const tag = await super.obtainFixedVersion(vimVersion);
			this.tags[version] = tag;
			return version;
		}
		return "";
	}
	async install(vimVersion) {
		await exec("xcode-select", ["-p"]);
		const tag = this.tags[vimVersion] || vimVersion;
		const reposPath = await this.cloneVim(tag);
		await backportPatch(reposPath, vimVersion, this.isGUI);
		process.env.LC_ALL = "C";
		const args = [];
		if (import_semver.lte(vimVersion, "8.2.2127", true)) {
			if (import_semver.lte(vimVersion, "8.2.2013", true)) args.push("--with-macarchs=x86_64");
			const patch = `
--- a/src/auto/configure
+++ b/src/auto/configure
@@ -4758,7 +4758,7 @@ fi
 $as_echo_n "checking if architectures are supported... " >&6; }
     save_cflags="$CFLAGS"
     save_ldflags="$LDFLAGS"
-    archflags=\`echo "$ARCHS" | sed -e 's/[[:<:]]/-arch /g'\`
+    archflags=\`echo "$ARCHS" | sed 's/[[:>:]][ ][ ]*[[:<:]]/ -arch /g' | sed 's/^/-arch /g'\`
     CFLAGS="$CFLAGS $archflags"
     LDFLAGS="$LDFLAGS $archflags"
     cat confdefs.h - <<_ACEOF >conftest.$ac_ext
      `.trim() + "\n";
			await exec("patch", ["-p1"], {
				cwd: reposPath,
				input: buffer.Buffer.from(patch)
			});
		}
		if (import_semver.lte(vimVersion, "8.2.5135", true)) args.push("CFLAGS=-Wno-implicit-int");
		await exec("./configure", args, { cwd: reposPath });
		await exec("make", [], { cwd: reposPath });
		await mkdirP(this.installDir);
		await cp(path.join(reposPath, "src", "MacVim", "build", "Release", "MacVim.app"), this.installDir, { recursive: true });
	}
	getPath() {
		return path.join(this.installDir, "MacVim.app", "Contents", "bin");
	}
};
