//#region src/installer/macvim_releases_installer.ts
function checkPath(targetPath) {
	try {
		const stat = fs.statSync(targetPath);
		return stat.isFile() || stat.isDirectory();
	} catch (_e) {
		return false;
	}
}
var MacVimReleasesInstaller = class extends ReleasesInstaller {
	repository = "macvim-dev/macvim";
	assetNamePatterns = [/^MacVim.*\.dmg$/];
	vimVersionPattern = /(?:Vim\s+patch|Updated\s+to\s+Vim)\s*(\d+\.\d+\.\d+)/i;
	toSemverString(release) {
		return this.vimVersionPattern.exec(release.description ?? "")?.[1] || "";
	}
	async install(vimVersion) {
		await exec("hdiutil", [
			"attach",
			"-quiet",
			"-mountpoint",
			"/Volumes/MacVim",
			await this.downloadAsset(vimVersion)
		]);
		await mkdirP(this.installDir);
		await cp("/Volumes/MacVim/MacVim.app", this.installDir, { recursive: true });
		await exec("hdiutil", ["detach", "/Volumes/MacVim"]);
	}
	getPath() {
		const vimPath = path.join(this.installDir, "MacVim.app", "Contents", "bin");
		if (checkPath(path.join(vimPath, "vim"))) return vimPath;
		const oldVimPath = path.join(this.installDir, "MacVim.app", "Contents", "MacOS");
		if (checkPath(path.join(oldVimPath, "Vim"))) return oldVimPath;
		throw new Error("Vim executable could not found");
	}
	getExecutableName() {
		if (checkPath(path.join(this.installDir, "MacVim.app", "Contents", "bin", "vim"))) return "vim";
		if (checkPath(path.join(this.installDir, "MacVim.app", "Contents", "MacOS", "Vim"))) return "Vim";
		throw new Error("Vim executable could not found");
	}
};
