var UnixVimBuildInstaller = class extends VimBuildInstaller {
	async install(vimVersion) {
		const reposPath = await this.cloneVim(vimVersion);
		await backportPatch(reposPath, vimVersion, this.isGUI);
		const args = [`--prefix=${this.installDir}`, "--with-features=huge"];
		const vimSemver = import_semver.coerce(vimVersion, { loose: true });
		if (process.platform === "darwin") {
			process.env.LC_ALL = "C";
			if (vimSemver && import_semver.lt(vimSemver, "8.2.5135", true)) args.push("CFLAGS=-Wno-implicit-int");
		}
		if (this.isGUI) {
			const [guiarg, guipkg] = vimSemver && import_semver.lt(vimSemver, "7.4.1402", true) ? ["gtk2", "libgtk2.0-dev"] : ["gtk3", "libgtk-3-dev"];
			await exec("sudo", ["apt-get", "update"]);
			await exec("sudo", [
				"apt-get",
				"install",
				"libxmu-dev",
				"libxpm-dev",
				guipkg
			]);
			args.push(`--enable-gui=${guiarg}`, "--enable-fail-if-missing");
		}
		await exec("./configure", args, { cwd: reposPath });
		await exec("make", [], { cwd: reposPath });
		await exec("make", ["install"], { cwd: reposPath });
	}
	getPath() {
		return path.join(this.installDir, "bin");
	}
};
